import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"57A. 10. Hour Break Not Given","description":"","frontmatter":{"title":"57A. 10. Hour Break Not Given","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","breaks"]},"headers":[],"relativePath":"ebas/mspp/hours-of-work/57A-10-hour-break-not-given.md","filePath":"ebas/mspp/hours-of-work/57A-10-hour-break-not-given.md"}'),s={name:"ebas/mspp/hours-of-work/57A-10-hour-break-not-given.md"};function i(n,e,h,u,d,p){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_57a-10-hour-break-not-given" tabindex="-1">57A. 10. Hour Break Not Given <a class="header-anchor" href="#_57a-10-hour-break-not-given" aria-label="Permalink to &quot;57A. 10. Hour Break Not Given&quot;">​</a></h1><p>This clause 57A takes effect from the day referred to in <a href="/eba/ebas/mspp/hours-of-work/57-employee-rosters.html">clause 57.6</a>(ii).</p><p><strong>57A.1</strong> Ordinary shifts without 10 hour break Where for urgent operational issues there is not at least ten hours off duty between successive ordinary shifts as required at 57.6(ii), the Employee shall either:</p><p><strong>a.</strong> be released from duty without loss of pay until the Employee has had 10 consecutive hours off duty, or</p><p><strong>b.</strong> be paid at the rate of double time until released from duty for such rest period, where the Employee is required to work without a 10 hour break on the instructions of the Employer.</p><p>Example: An Employee finishes ordinary rostered duty at midnight and is rostered to commence their next ordinary hours shift at 8am. Under subclause 62A.1(a), the Employee attends at 10 a.m. and receives two (2) hours ordinary pay for the hours 8.00am to 10.00am plus ordinary time for the balance of the shift. Under subclause 62A.1((b), the Employee is required by the Employer to attend at 8am and is paid at the rate of double time for the entire shift. Where there is not at least ten hours off duty between successive ordinary shifts as required at subclause 57.6a(ii), in deciding what approach to take the Employer must consider the occupational health and safety of the Employee.</p><p>Plain language terms: ten hour break, 10hr break.</p>',7)])])}const m=t(s,[["render",i]]);export{f as __pageData,m as default};
